    "script/Apps/RocketL/index.html": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Rocket League</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\nhtml,body{width:100%;height:100%;background:#0a0a0a;overflow:hidden;font-family:system-ui,-apple-system,sans-serif}\n#launcher{position:fixed;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:28px;background:radial-gradient(ellipse at 60% 40%,rgba(26,95,168,0.18) 0%,transparent 65%),#0a0a0a;z-index:10;transition:opacity 0.4s}\n.icon{width:80px;height:80px;background:linear-gradient(135deg,#1a5fa8,#0f3d70);border-radius:22px;display:flex;align-items:center;justify-content:center;font-size:36px;box-shadow:0 8px 32px rgba(26,95,168,0.5)}\n.title{color:#fff;font-size:28px;font-weight:700;letter-spacing:-0.5px}\n.desc{color:rgba(255,255,255,0.45);font-size:14px}\n.btn-wrap{display:flex;gap:12px;margin-top:4px}\n.btn{padding:14px 28px;border-radius:12px;font-size:15px;font-weight:600;cursor:pointer;border:none;transition:transform 0.15s}\n.btn-primary{background:linear-gradient(135deg,#1a5fa8,#0f3d70);color:#fff;box-shadow:0 4px 20px rgba(26,95,168,0.4)}\n.btn-secondary{background:rgba(255,255,255,0.08);color:rgba(255,255,255,0.8);border:1px solid rgba(255,255,255,0.12)}\n.btn:hover{transform:translateY(-2px)}\n.note{color:rgba(255,255,255,0.25);font-size:12px;text-align:center;max-width:300px;line-height:1.6}\niframe{position:fixed;inset:0;width:100%;height:100%;border:none}\n</style>\n</head>\n<body>\n<div id=\"launcher\">\n  <div class=\"icon\">&#128663;</div>\n  <div class=\"title\">Rocket League</div>\n  <div class=\"desc\">Play via CINE Stream</div>\n  <div class=\"btn-wrap\">\n    <button class=\"btn btn-primary\" onclick=\"openTab()\">Open App</button>\n    <button class=\"btn btn-secondary\" onclick=\"tryEmbed()\">Try In-Window</button>\n  </div>\n  <p class=\"note\">For the best gaming experience, open in a new tab.</p>\n</div>\n<iframe id=\"ifr\" style=\"display:none\" allow=\"autoplay;fullscreen;gamepad;microphone;camera\" referrerpolicy=\"no-referrer\"></iframe>\n<script>\nvar _u=atob('aHR0cDovL3N0cmVhbWV4LnNo');\nfunction openTab(){window.open(_u,'_blank');}\nfunction tryEmbed(){\n  var f=document.getElementById('ifr');\n  f.style.display='block';\n  document.getElementById('launcher').style.opacity='0';\n  document.getElementById('launcher').style.pointerEvents='none';\n  setTimeout(function(){f.src=_u;},0);\n}\n</script>\n</body>\n</html>\n",
    "script/Apps/Xbox/index.html": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Xbox Cloud Gaming</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\nhtml,body{width:100%;height:100%;background:#0a0a0a;overflow:hidden;font-family:system-ui,-apple-system,sans-serif}\n#launcher{position:fixed;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:28px;background:radial-gradient(ellipse at 60% 40%,rgba(16,124,16,0.18) 0%,transparent 65%),#0a0a0a;z-index:10;transition:opacity 0.4s}\n.icon{width:80px;height:80px;background:linear-gradient(135deg,#107c10,#0a5f0a);border-radius:22px;display:flex;align-items:center;justify-content:center;font-size:36px;box-shadow:0 8px 32px rgba(16,124,16,0.5)}\n.title{color:#fff;font-size:28px;font-weight:700;letter-spacing:-0.5px}\n.desc{color:rgba(255,255,255,0.45);font-size:14px}\n.btn-wrap{display:flex;gap:12px;margin-top:4px}\n.btn{padding:14px 28px;border-radius:12px;font-size:15px;font-weight:600;cursor:pointer;border:none;transition:transform 0.15s,box-shadow 0.15s}\n.btn-primary{background:linear-gradient(135deg,#107c10,#0a5f0a);color:#fff;box-shadow:0 4px 20px rgba(16,124,16,0.4)}\n.btn-secondary{background:rgba(255,255,255,0.08);color:rgba(255,255,255,0.8);border:1px solid rgba(255,255,255,0.12)}\n.btn:hover{transform:translateY(-2px)}\n.note{color:rgba(255,255,255,0.25);font-size:12px;text-align:center;max-width:300px;line-height:1.6}\niframe{position:fixed;inset:0;width:100%;height:100%;border:none}\n</style>\n</head>\n<body>\n<div id=\"launcher\">\n  <div class=\"icon\">&#9711;</div>\n  <div class=\"title\">Xbox Cloud Gaming</div>\n  <div class=\"desc\">Play Xbox games in the browser</div>\n  <div class=\"btn-wrap\">\n    <button class=\"btn btn-primary\" onclick=\"openTab()\">Open Xbox</button>\n    <button class=\"btn btn-secondary\" onclick=\"tryEmbed()\">Try In-Window</button>\n  </div>\n  <p class=\"note\">Xbox requires a Microsoft account and blocks embedding. Opening in a new tab is required.</p>\n</div>\n<iframe id=\"ifr\" style=\"display:none\" allow=\"autoplay;fullscreen;gamepad;microphone;camera\" referrerpolicy=\"no-referrer\"></iframe>\n<script>\nvar _u=atob('aHR0cHM6Ly93d3cueGJveC5jb20vZW4tdXMvcGxheQ==');\nfunction openTab(){window.open(_u,'_blank');}\nfunction tryEmbed(){\n  var f=document.getElementById('ifr');\n  f.style.display='block';\n  document.getElementById('launcher').style.opacity='0';\n  document.getElementById('launcher').style.pointerEvents='none';\n  setTimeout(function(){f.src=_u;},0);\n}\n</script>\n</body>\n</html>\n",
